<?php
declare(strict_types=1);
header('Content-Type: application/json; charset=utf-8');
function respond(int $code,bool $ok,string $message):never{http_response_code($code);echo json_encode(['success'=>$ok,'message'=>$message],JSON_UNESCAPED_UNICODE);exit;}
if(($_SERVER['REQUEST_METHOD']??'')!=='POST')respond(405,false,'Dozwolona jest wyłącznie metoda POST.');
if(!empty($_POST['website']??''))respond(200,true,'Zgłoszenie zostało przyjęte.');
