$allowedRoles=['Generalny wykonawca','Wykonawca','Podwykonawca','Dostawca materiałów','Producent materiałów','Inżynier, projektant lub architekt','Usługodawca dla budownictwa','Inna'];$allowedSizes=['1–2 osoby','3–10 osób','11–50 osób','51–250 osób','Powyżej 250 osób'];
$roles=array_values(array_unique(array_filter(array_map('strval',is_array($_POST['role']??null)?$_POST['role']:[]),fn($v)=>in_array($v,$allowedRoles,true))));
